// DimensionsLabel formats a width/height pair as "W × H", or "" when either is
// missing (a document). Used by the web layer to build cards.
func DimensionsLabel(w, h *int) string {
	if w == nil || h == nil {
		return ""
	}
	return fmt.Sprintf("%d × %d", *w, *h)
}

